"""Draft-only Web Intelligence and content-context handoffs."""
from intelligence_director.models import ContentOpportunityContext,IntelligenceSignal,ResearchDepthRecommendation,ResearchPriorityScore,WebResearchPlanRequest
def create_web_plan_request(signal:IntelligenceSignal,score:ResearchPriorityScore,depth:ResearchDepthRecommendation,domains:list[str])->WebResearchPlanRequest:
    return WebResearchPlanRequest(objective=f"Verify: {signal.topic}",research_question=f"What current public evidence supports {signal.topic}?",priority=score.overall,research_depth=depth.depth,approved_domains=domains,official_sources_expected=depth.expected_sources[:1],maximum_pages=depth.maximum_pages,maximum_duration_seconds=depth.maximum_duration_seconds,expected_evidence=depth.expected_evidence,prohibited_actions=["login","forms","downloads","uploads","publishing","private pages"],freshness_deadline=depth.freshness_deadline,founder_approval_required=True,live_execution=False)
def create_content_context(signal:IntelligenceSignal,*,verified_facts:list[str],unresolved:list[str],prohibited:list[str],deadline)->ContentOpportunityContext:
    return ContentOpportunityContext(topic=signal.topic,verified_facts=verified_facts,unresolved_claims=unresolved,prohibited_claims=prohibited,freshness_deadline=deadline,audience="Founder-defined target audience",business_objective="Evaluate an evidence-supported content opportunity",likely_platform="Founder selection required",content_gap="Requires founder review",evidence_visuals=[],monetization_hypothesis="Unverified hypothesis; no revenue guarantee",research_completeness=signal.confidence,mission_executed=False,published=False)
